class Common_Model_Eshop extends Common_Model_Base_Eshop {

    const HADEX_CZ_ID = 1;

    /**
     * @param int|null $User_ID
     * @return Common_Model_Eshop[]|Doctrine_Collection
     */
    public static function getEshops(?int $User_ID = null): array|Doctrine_Collection {
        $query = Doctrine_Query::create();
        $query->from('Common_Model_Eshop object');
        if ($User_ID && UserModel::getUser($User_ID)->Type !== UserModel::TYPE_SUPERADMIN)
            $query->innerJoin('object.userEshops userEshops WITH userEshops.User_ID = ?', $User_ID);

        return $query->execute();
    }

    /**
     * Vrací první eshop, který může uživatel editovat
     * @return Common_Model_Eshop|array|Doctrine_Collection|null
     */
    public static function getFirstEshop(): Common_Model_Eshop|array|Doctrine_Collection|null {
        $eshop = self::getEshops();
        return !empty($eshop)?$eshop[0]:null;
    }

    /**
     * @param string $url
     * @return Common_Model_Eshop|null
     */
    public static function getEshopByURL(string $url): ?Common_Model_Eshop {
        $query = Doctrine_Query::create();
        $query->from('Common_Model_Eshop object');
        $query->where('object.URL LIKE ?', '%' . $url);
        $query->andWhere('object.Active = ?', true);
        $query->innerJoin('object.settings settings');
        $query->leftJoin('object.language language');
        $query->leftJoin('object.currency currency');

        /** @var \Common_Model_Eshop $eshop */
        $eshop = $query->fetchOne();

        //$eshop->language->Code;

        return $eshop ?: null;
    }

    /**
     * @param int $ID
     * @return self|null
     */
    public static function getEshopByID(int $ID): ?self {
        $query = Doctrine_Query::create();
        $query->from('Common_Model_Eshop object');
        $query->where('object.ID = ?', $ID);
        $query->andWhere('object.Active = ?', true);
        $query->leftJoin('object.settings settings');
        $query->leftJoin('object.currency currency');
        $query->leftJoin('object.language language');

        /** @var self $eshop */
        $eshop = $query->fetchOne();

        return $eshop ?: null;
    }

    /**
     * @return string
     */
    public function getURL(): string {
        return $this->URL;
    }

    /**
     * Vrací, zda je uživatel oprávněn editovat eshop
     * @param int $User_ID
     * @return bool
     */
    public function hasAccess(int $User_ID): bool {
        $user = UserModel::getUser($User_ID);
        if ($user && $user->isSuperadmin())
            return true;

        foreach ($this->userEshops as $userEshop) {
            if ($userEshop->User_ID == $User_ID)
                return true;
        }

        return false;
    }
}